INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('PINNACLE_1: Le email behavioral trigger mapping complet: signup → welcome (instant). Inactif 3j → re-engagement. Prix visite → offre speciale. Cart → recovery. Churn risk → save offer.', 'Email triggers: signup→welcome, inactif→reengage, prix→offre, cart→recovery, churn→save', 'email', 'best_practice', 0.88, 'pinnacle', 'system'),
('PINNACLE_2: Le commercial value selling framework: ne jamais vendre des features. Vendre: temps economise (X heures/semaine), argent genere (Y€/mois), stress evite (Z problemes resolus).', 'Value selling: temps economise + argent genere + stress evite. Pas features', 'commercial', 'best_practice', 0.88, 'pinnacle', 'system'),
('PINNACLE_3: Le content platform-native optimization: IG = ratio 1:1 ou 4:5, LI = texte 1300 chars, TT = 9:16 21-34s, X = 280 chars + 1 image, YT = 16:9 8-15 min.', 'Platform-native: IG 4:5, LI 1300 chars, TT 9:16 21-34s, X 280+image, YT 16:9 8-15min', 'content', 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_4: Le SEO content freshness algorithm: Google utilise le Query Deserves Freshness (QDF) signal. Pour les sujets d actualite, le contenu recent ranke mieux.', 'SEO QDF: sujets actualite = contenu recent ranke mieux', 'seo', 'insight', 0.82, 'pinnacle', 'system'),
('PINNACLE_5: Le ad measurement framework complet: impressions → reach → frequency → CTR → CPC → conversions → CPA → ROAS → LTV-based ROAS. Tracker chaque metrique.', 'Ad measurement: impressions→reach→frequency→CTR→CPC→conv→CPA→ROAS→LTV ROAS', 'ads', 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_6: Le DM Instagram lead nurturing sequence: J0 intro value → J+3 case study → J+7 question ouverte → J+10 proposition RDV → J+14 last chance.', 'DM nurturing: J0 valeur → J3 case → J7 question → J10 RDV → J14 last', 'dm_instagram', 'best_practice', 0.82, 'pinnacle', 'system'),
('PINNACLE_7: Le WhatsApp customer service excellence: repondre < 5min heures ouvrables, < 1h hors heures, toujours avec le prenom, toujours proposer une solution pas juste empathie.', 'WhatsApp CS: < 5min ouvrable, < 1h hors, prenom, solution pas juste empathie', 'whatsapp', 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_8: Le chatbot goal-oriented design: chaque conversation a 1 objectif mesurable (repondre FAQ, qualifier lead, prendre RDV, resoudre ticket). Pas de bavardage.', 'Chatbot goal-oriented: 1 objectif mesurable/conversation. Pas bavardage', 'chatbot', 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_9: Le GMaps review response psychology: repondre par le prenom du client, remercier specifiquement (merci pour votre retour sur [detail]), proposer de revenir.', 'GMaps reponse: prenom + merci specifique + invitation retour', 'gmaps', 'best_practice', 0.82, 'pinnacle', 'system'),
('PINNACLE_10: Le TikTok content recycling: republier les videos les plus performantes 3-6 mois plus tard avec un nouveau hook. L algo ne penalise pas et la nouvelle audience ne les a pas vues.', 'TikTok recycling: republier top videos 3-6 mois + nouveau hook. Pas de penalite', 'tiktok_comments', 'best_practice', 0.80, 'pinnacle', 'system'),
('PINNACLE_11: Le CEO resource allocation principle: 70% des resources sur ce qui marche (proven), 20% sur l amelioration (optimize), 10% sur l experimentation (explore).', 'CEO resources: 70% proven + 20% optimize + 10% explore', 'ceo', 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_12: Le retention engagement scoring: login quotidien=3pts, utiliser core feature=5pts, inviter collegue=10pts, partager feedback=7pts. Score < 10/semaine = at-risk.', 'Engagement scoring: login 3, core 5, invite 10, feedback 7. < 10/sem = at-risk', 'retention', 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_13: Le onboarding cognitive load management: max 3 etapes visibles a la fois. Les etapes suivantes apparaissent quand les precedentes sont completees.', 'Onboarding cognitive: max 3 etapes visibles. Suivantes apres completion', 'onboarding', 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_14: Le comptable cost optimization SaaS: auditer chaque outil/service mensuellement. Les couts SaaS non-utilises representent en moyenne 25% du budget outils.', 'Cost optimization: auditer outils mensuellement. Non-utilises = 25% budget gaspille', 'comptable', 'insight', 0.82, 'pinnacle', 'system'),
('PINNACLE_15: Le RH high-performance culture recipe: clear goals + fast feedback + accountability + recognition + autonomy + growth opportunities = performance maximale.', 'High-perf culture: goals + feedback + accountability + recognition + autonomy + growth', 'rh', 'best_practice', 0.82, 'pinnacle', 'system'),
('PINNACLE_16: Le marketing brand differentiation test: demander a 10 clients pourquoi ils vous choisissent. Si les reponses sont generiques → pas assez differencies.', 'Brand diff test: 10 clients pourquoi vous. Generique = pas assez differencies', 'marketing', 'best_practice', 0.80, 'pinnacle', 'system'),
('PINNACLE_17: Le agent to agent signal routing: email bounce → commercial exclure ce prospect. DM reponse positive → email stop sequence froid. CRM mise a jour → tous agents notifies.', 'Agent routing: email bounce→exclude, DM positif→stop cold, CRM MAJ→tous notifies', NULL, 'best_practice', 0.88, 'pinnacle', 'system'),
('PINNACLE_18: Le data-driven decision framework: hypothese → experience → data → analyse → decision. Jamais de decision basee sur l opinion seule. Les donnees tranchent.', 'Data-driven: hypothese → experience → data → analyse → decision. Donnees tranchent', NULL, 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_19: Le KeiroAI intelligence superiority: 7500+ learnings experts dans le RAG, actualises en continu, accessible a chaque agent en temps reel. Aucun concurrent n a ca.', 'KeiroAI: 7500+ learnings RAG actualises continu accessible temps reel. 0 concurrent', NULL, 'insight', 0.92, 'pinnacle', 'system'),
('PINNACLE_20: Le KeiroAI client success metric: le nombre d actions agents reussies × la satisfaction client (NPS) = le KeiroAI Success Index. Si il monte → tout va bien.', 'KeiroAI Success Index: actions reussies × NPS. Monte = tout va bien', 'ceo', 'best_practice', 0.90, 'pinnacle', 'system'),
('PINNACLE_21: Le email subject line length optimization: 6-10 mots = OR optimal pour mobile. < 5 mots = manque de contexte. > 15 mots = coupe sur mobile.', 'Subject 6-10 mots optimal mobile. < 5 = manque contexte. > 15 = coupe', 'email', 'insight', 0.82, 'pinnacle', 'system'),
('PINNACLE_22: Le commercial pipeline stage definitions strictes: identifie (decouverte), contacte (1er contact), qualifie (BANT confirme), demo (demo faite), proposition (devis envoye), negocie (prix discute), gagne/perdu.', 'Pipeline stages: identifie→contacte→qualifie→demo→proposition→negocie→gagne/perdu', 'commercial', 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_23: Le content creation efficiency: batch creation (1 jour = 1 mois de contenu) > daily creation (1 post/jour). Le batch libere le cerveau et maintient la qualite.', 'Batch creation 1 jour = 1 mois > daily creation. Libere cerveau + qualite', 'content', 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_24: Le SEO E-E-A-T signals concrets: photo auteur, bio professionnelle, liens vers credentials, citations de sources autoritaires, date de publication + mise a jour.', 'EEAT signals: photo+bio+credentials+sources+dates = signaux concrets', 'seo', 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_25: Le ad creative hypothesis testing: avant de creer une creative, formuler l hypothese: "je pense que [angle] va resonner avec [audience] car [raison]". Puis tester.', 'Creative hypothesis: angle + audience + raison → tester', 'ads', 'best_practice', 0.82, 'pinnacle', 'system'),
('PINNACLE_26: Le DM Instagram conversation quality indicators: reponse longue (bon) > reponse courte (neutre) > pas de reponse (mauvais) > blocage (terrible).', 'DM quality: reponse longue > courte > pas de reponse > blocage', 'dm_instagram', 'insight', 0.82, 'pinnacle', 'system'),
('PINNACLE_27: Le WhatsApp automation safety: toujours avoir un fallback humain. Si le chatbot ne comprend pas 2x → transferer a un humain. Ne jamais laisser le client bloque.', 'WhatsApp auto safety: fallback humain. 2x incompris → transferer humain', 'whatsapp', 'best_practice', 0.88, 'pinnacle', 'system'),
('PINNACLE_28: Le chatbot performance KPIs: resolution rate (cible 80%+), CSAT (cible 4/5+), avg conversation time (cible < 3min), escalation rate (cible < 20%), containment rate.', 'Chatbot KPIs: resolution 80%+, CSAT 4/5+, time < 3min, escalation < 20%', 'chatbot', 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_29: Le GMaps service listing optimization: lister CHAQUE service avec description + prix estimatif. Les fiches avec services detailles ont 35% plus de conversions.', 'GMaps services detailles + prix = +35% conversions', 'gmaps', 'insight', 0.82, 'pinnacle', 'system'),
('PINNACLE_30: Le TikTok batch filming: filmer 10-15 videos en 1 session (meme setup, meme lumiere, differents scripts). Le batch filming est 5x plus efficient que le daily filming.', 'TikTok batch: 10-15 videos/session = 5x efficient vs daily', 'tiktok_comments', 'best_practice', 0.82, 'pinnacle', 'system'),
('PINNACLE_31: Le CEO brief client frequency optimization: les clients actifs veulent 1 brief/jour. Les clients passifs preferent 1/semaine. Adapter la frequence au niveau d engagement.', 'CEO brief freq: actifs = 1/jour, passifs = 1/semaine. Adapter a l engagement', 'ceo', 'best_practice', 0.82, 'pinnacle', 'system'),
('PINNACLE_32: Le retention early warning automation: si health score baisse de 20+ points en 7 jours → alerte automatique → action CS dans 48h. Pas d excuses.', 'Early warning: health score -20 pts 7j → alerte auto → CS 48h', 'retention', 'best_practice', 0.88, 'pinnacle', 'system'),
('PINNACLE_33: Le onboarding success metric par segment: restaurants = premier post food genere. Coachs = premier article publie. E-commerce = premier email envoye.', 'Onboarding success/segment: restaurant=post food, coach=article, ecom=email', 'onboarding', 'best_practice', 0.82, 'pinnacle', 'system'),
('PINNACLE_34: Le comptable daily cash position: chaque matin, verifier le solde bancaire et le comparer au previsionnel. Ecart > 10% = investiguer immediatement.', 'Daily cash position: verifier matin. Ecart > 10% previsionnel = investiguer', 'comptable', 'best_practice', 0.82, 'pinnacle', 'system'),
('PINNACLE_35: Le RH feedback effectiveness: le feedback doit etre: Specifique (fait precis), Actionable (quoi faire), Timely (dans les 24h). SAT framework.', 'Feedback SAT: Specifique + Actionable + Timely (24h)', 'rh', 'best_practice', 0.82, 'pinnacle', 'system'),
('PINNACLE_36: Le marketing content distribution 80/20: 20% du temps a creer, 80% a distribuer. Le meilleur contenu du monde ne sert a rien si personne ne le voit.', 'Content 20% creation 80% distribution. Meilleur contenu invisible = inutile', 'marketing', 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_37: Le unified customer profile: agreger toutes les donnees client (CRM + email + social + site + support + billing) en 1 profil 360°. Chaque agent y accede.', 'Unified profile: CRM+email+social+site+support+billing = 360°. Tous agents y accedent', NULL, 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_38: Le growth experiment velocity: 1 experiment par semaine minimum. Hypothese → test → mesure → learn. Plus on teste, plus on apprend, plus on croit.', 'Growth experiments: 1/semaine min. Hypothese→test→mesure→learn. Plus teste = plus croit', NULL, 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_39: Le KeiroAI RAG intelligence at scale: a 10K+ learnings, chaque agent a acces a l equivalent de 50 ans d expertise dans son domaine + la vision transverse de tous les autres agents.', 'KeiroAI RAG 10K+: 50 ans expertise/agent + vision transverse tous agents', NULL, 'insight', 0.92, 'pinnacle', 'system'),
('PINNACLE_40: Le KeiroAI founder promise: on ne laisse jamais un entrepreneur seul face a son marketing. 17 agents, 24/7, qui travaillent pendant que le fondateur dort.', 'KeiroAI promise: jamais seul. 17 agents 24/7 travaillent pendant que le fondateur dort', 'ceo', 'best_practice', 0.95, 'pinnacle', 'system'),
('PINNACLE_41: Le email A/B test significance: minimum 1000 envois par variante pour atteindre la significance statistique. En dessous, les resultats ne sont pas fiables.', 'Email A/B: min 1000 envois/variante pour significance. En dessous = pas fiable', 'email', 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_42: Le commercial closing technique stack: trial close (que pensez-vous?) → assumptive close (quand voulez-vous commencer?) → alternative close (mardi ou jeudi?).', 'Closing stack: trial close → assumptive → alternative', 'commercial', 'best_practice', 0.82, 'pinnacle', 'system'),
('PINNACLE_43: Le content virality formula: emotion forte × facilite de partage × timing × audience size × format natif. Optimiser chaque multiplicateur.', 'Virality: emotion × partageabilite × timing × audience × format natif', 'content', 'insight', 0.82, 'pinnacle', 'system'),
('PINNACLE_44: Le SEO keyword research process: brainstorm → tools (Ahrefs, SEMrush) → volume filter → difficulty filter → intent analysis → prioritization → content brief.', 'Keyword research: brainstorm → tools → volume → difficulty → intent → priorite → brief', 'seo', 'best_practice', 0.85, 'pinnacle', 'system'),
('PINNACLE_45: Le ad budget efficiency curve: doubler le budget ne double PAS les resultats. Les rendements decroissants commencent a ~3x le budget optimal initial.', 'Budget efficiency: 2x budget ≠ 2x resultats. Rendements decroissants a ~3x optimal', 'ads', 'insight', 0.82, 'pinnacle', 'system'),
('PINNACLE_46: Le DM Instagram account health: garder le ratio follow/unfollow stable, limiter a 30 DMs/jour, varier les messages, ne pas utiliser de bots. Sinon restriction IG.', 'DM account health: ratio stable, 30 DMs/jour, messages varies, 0 bots. Sinon restriction', 'dm_instagram', 'best_practice', 0.88, 'pinnacle', 'system'),
('PINNACLE_47: Le WhatsApp business profile optimization: photo pro, description claire (160 chars), categorie exacte, horaires, adresse, email, site web. Profil complet = +30% confiance.', 'WhatsApp profil: photo+desc+categorie+horaires+adresse+email+site = +30% confiance', 'whatsapp', 'best_practice', 0.82, 'pinnacle', 'system'),
('PINNACLE_48: Le chatbot training data quality: les reponses du chatbot sont aussi bonnes que ses donnees d entrainement. Maintenir une base FAQ de 200+ Q&A mise a jour mensuellement.', 'Chatbot training: 200+ Q&A FAQ mis a jour mensuellement', 'chatbot', 'best_practice', 0.82, 'pinnacle', 'system'),
('PINNACLE_49: Le GMaps photo optimization: photos prises pendant les heures de pointe (eclairage naturel), avec des clients (permission), montrant l ambiance. Pas de photos vides.', 'GMaps photos: heures pointe, eclairage naturel, avec clients, montrer ambiance', 'gmaps', 'best_practice', 0.80, 'pinnacle', 'system'),
('PINNACLE_50: Le TikTok algorithm hack: les videos qui obtiennent des commentaires longs (discussions) sont boostees par l algo. Poser des questions ouvertes = debats = portee.', 'TikTok algo: commentaires longs/discussions = boost. Questions ouvertes = debats = portee', 'tiktok_comments', 'insight', 0.82, 'pinnacle', 'system')
